var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이지수 씨의 말대로라면 이 좌표 어딘가에 있을 겁니다.","JPN":"ムラサメさんの言葉通りだとすると、この座標のどこかにいるはずです。","ENG":"According to Lee Jisoo, it should be somewhere around these coordinates.","TWN":"如果依照李智秀說的，那孩子應該就在這個座標某處。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"정말로 그 아이가... 이런 이면세계 어딘가에 있다고?","JPN":"本当にあの子が……こんな裏世界のどこかにいるの？","ENG":"That child is really somewhere in the Counterside...?","TWN":"真的嗎？那孩子……真的在這個異界某處？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"근거는 충분해.","JPN":"根拠は十分だ。","ENG":"The evidence is sufficient.","TWN":"證據很充分。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당신이 가진 그 아이와의 인연을 따라온 거니까.","JPN":"お前の持つ、子との絆を辿ってきたんだからな。","ENG":"We followed the bond you share with that child.","TWN":"因為我們跟隨你和那孩子的緣分來到這裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나와 그 아이의... 인연?","JPN":"私とあの子の……絆？","ENG":"A bond... between me and that child?","TWN":"我和那孩子的……緣分？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아니, 그런 게 진짜로 당신 눈에 보인다고 해도 말이지...","JPN":"本当にそんなものがあなたに見えるとして……","ENG":"No, even if you really can see something like that...","TWN":"即便你真的能看到……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당장 세상이 멸망하게 생겼는데, 한가롭게 날 돕고 있어도 괜찮은 거야?","JPN":"すぐにでも世界が滅亡するって時に、のんびり私を手伝っていてもいいのか？","ENG":"The world's on the verge of ending, and you're helping me like this?","TWN":"現在世界即將毀滅，這麼悠哉幫我也沒問題嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"타기리온이란 마왕이 어디 숨어있는지 찾아야 한다면서?","JPN":"タギリオンという魔王がどこに隠れてるのか、探さなくちゃならないんだろう？","ENG":"Didn't you say you had to find the Demon Lord Thagirion?","TWN":"你不是說要找到魔王塔基里翁藏在哪嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"약속드렸잖아요.","JPN":"約束しましたからね。","ENG":"We made a promise, didn't we?","TWN":"我答應過你啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저희가 서생 씨를 찾는 걸 도와주면, 저희도 부인을 돕겠다고 했으니까요.","JPN":"ショウさんを探すのを手伝ってくれれば、僕たちも夫人を手伝うと。","ENG":"We told you that if you helped us find Seosaeng, we'd help you in return.","TWN":"如果幫我們找到書生，我們也會幫你。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그리고 부인의 아이를 찾도록 돕는 건, 타기리온을 찾는다는 저희 목적과도 일치하는 면이 있거든요.","JPN":"それに夫人のお子さんを探すのを手伝うのは、タギリオンを探すという僕たちの目的とも重なる部分があるんです。","ENG":"And helping you find your child also works toward our goal of locating Thagirion.","TWN":"而且幫你找到孩子，和我們尋找塔基里翁的目標也有些重疊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"마왕을 찾는 게... 그 아이랑 무슨 연관이 있다는 거지?","JPN":"魔王を探すのが……あの子と何の関係がある？","ENG":"Finding the Demon Lord... what does that have to do with that child?","TWN":"尋找魔王……和孩子有什麼關聯？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"정확히는 북방합의체의 연구와 연관이 있지.","JPN":"正確には北方合意体の研究と関係がある。","ENG":"More precisely, it's connected to research conducted by the Northern Union.","TWN":"確切來說，是與北方和議會的研究有關。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"북방합의체?","JPN":"北方合意体？","ENG":"The Northern Union?","TWN":"北方和議會？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그들은 과거, 이면세계 한복판에서 살아있는 거대한 유기체를 발견하고 연구했어.","JPN":"彼らは過去、裏世界の真ん中で生きている巨大な有機体を発見し研究した。","ENG":"In the past, they discovered a massive living organism in the middle of the Counterside and began studying it.","TWN":"他們曾在異界中心發現一個活著的巨大有機體，並對此進行研究。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그리고 연구 끝에, 그것이 행성 하나를 감쌀 만큼 거대한 나무의 일부라는 걸 밝혀냈지.","JPN":"そして研究の末、それが惑星を丸ごと包み込めるほど巨大な木の一部だということを突き止めたんだ。","ENG":"After years of research, they determined it was part of a colossal tree large enough to envelop an entire planet.","TWN":"研究後發現，那是包覆整個行星的巨樹的一部分。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나무라면 설마...","JPN":"木って、まさか……","ENG":"A tree... You don't mean–","TWN":"那棵樹該不會……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"도시의 대균열에 나타난 그것과 연관이 있는 건가?","JPN":"都市の大亀裂に現れたあれと関係があるのか？","ENG":"Is it connected to the one that appeared in the Grand Dimension Crevice above the city?","TWN":"和城市大峽谷中出現的那個有關嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래.","JPN":"そうだ。","ENG":"Yes.","TWN":"是啊。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"과학자들이 청동나무라 부르는 이 나무가 발견된 이면세계도, 한때는 사람이 살던 평범한 세상이었다네.","JPN":"科学者たちが青銅の木と呼んでいるこの木が発見された裏世界も、かつては人の住む平凡な世界だった。","ENG":"The part of the Counterside where scientists discovered this tree they call the Bronze Tree was once an ordinary world where people lived.","TWN":"被科學家稱為青銅樹的那棵樹發現的異界，也是曾有人居住的普通世界。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하지만 거대한 뿌리가 나타나, 세상의 모든 가능성을 빨아들이면서 지금의 황폐한 모습이 되고 말았지.","JPN":"だが巨大な根が現れ、世界のすべての可能性を吸い取られて、今のように荒れてしまったんだ。","ENG":"But a massive root appeared and absorbed every possibility within the world, leaving it in the desolate state you see now.","TWN":"但巨大的根出現後吸收了世界的所有可能性，變成了現在荒蕪的模樣。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"터무니 없는 얘기지 않나?","JPN":"とんでもない話だと思うだろう？","ENG":"Hard to believe, isn't it?","TWN":"這故事也太誇張了吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"누구도 쉽게 납득하지 못할 걸세. 그런 걸 직접 겪어보기 전까진 말이야.","JPN":"簡単に納得できる人なんていないさ。身をもって経験するまではね。","ENG":"No one would accept such a story easily. Not unless they experienced it themselves.","TWN":"除非親眼見到，否則沒有人會輕易相信。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 나무를 조종하는 게 마왕 타기리온이란 작자인가?","JPN":"その木を操っているのが魔王タギリオンという奴なのか？","ENG":"So the one controlling that tree is the Demon Lord Thagirion?","TWN":"操控那棵樹的就是魔王塔基里翁嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그렇기 때문에 우리가 타기리온을 찾으려면 그 나무의 원류를 찾아 거슬러가야 한다네.","JPN":"だから我々がタギリオンを探し出すには、その木の源を見つけて、遡らなければならないのさ。","ENG":"That's why, if we want to find Thagirion, we must trace the origin of that tree.","TWN":"所以如果我們要找到塔基里翁，就得追溯到樹的源頭。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그리고 자네 아이가 그 나무의 정수를 품고 있지.","JPN":"そして君の子どもがその木の精髄を持っている。","ENG":"And your child carries the essence of that tree.","TWN":"而你的孩子擁有那樹的精華。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"청동나무의... 심장.","JPN":"青銅の木の……心臓。","ENG":"The Bronze Tree's... heart.","TWN":"青銅樹的……心臟。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그게 우리가 그 흔적을 쫓는 이유다.","JPN":"私たちがその痕跡を追っている理由だ。","ENG":"That's why we're following its traces.","TWN":"這就是我們追蹤痕跡的原因。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"모든 것은 본질로 되돌아가기 마련이니까.","JPN":"すべては本質に戻るものだからな。","ENG":"Everything eventually returns to its origin.","TWN":"萬物終將回歸本質。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"뭔가 보이기 시작했군.","JPN":"何かが見えてきた。","ENG":"Something's starting to appear.","TWN":"我開始有點看懂了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"오...","JPN":"おお……","ENG":"Oh...","TWN":"哦……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이면세계 탐사는 여러 번 다녀봤지만, 이런 광경은 처음이네요.","JPN":"裏世界の探査には何度か行ってますけど、こんな光景は初めてですね。","ENG":"I've explored the Counterside several times, but I've never seen a sight like this.","TWN":"我探訪異界很多次，但是第一次見到這種景象。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"꼭 요정이라도 나타날 것 같아요.","JPN":"まるで妖精でも出てきそうです。","ENG":"It almost feels like a fairy might appear.","TWN":"彷彿精靈會出現一樣。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"정말이네.","JPN":"本当だ。","ENG":"You're right.","TWN":"真的耶。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어제 꽃을 꺾어간 자리에 그 꽃이 멀쩡히 남아있어.","JPN":"昨日花を摘んだ場所に、同じ花が同じ姿で残ってる。","ENG":"The flower that was picked yesterday is still here, perfectly intact.","TWN":"昨天摘下的花，今天又好好地在那裡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이런 식으로 매일... 모든 게 원래 자리로 돌아오는 거구나.","JPN":"こんな風に毎日……すべてが元通りになるんだね。","ENG":"So every day... Everything returns to its original place.","TWN":"每天都是如此……所有一切都回到原點。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"꺾여도 사라지지 않으면 시들 일도 없지.","JPN":"摘んでも消えないのだから、枯れることもないわ。","ENG":"If it doesn't disappear after being picked, it won't ever wither either.","TWN":"即使摘下也不會凋謝。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"최초의 주민은 꽃이 시드는 걸 좋아하지 않으니 말이야.","JPN":"最初の住民は花が枯れるのが嫌なのよ。","ENG":"The First Resident doesn't like flowers wilting, after all.","TWN":"因為最初的居民不喜歡花凋謝。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"최초의 주민이요?","JPN":"最初の住民？","ENG":"The First Resident?","TWN":"最初的居民？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그래. 낙원의 주민들은 다들 어렴풋이 알고 있단다.","JPN":"そう。楽園の住民はみんな、なんとなく分かっているの。","ENG":"Yes. The residents of the Promised Land all know it vaguely.","TWN":"對，樂園居民都隱約知道。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"낙원은 모두의 소망을 이뤄주는 곳.","JPN":"楽園はみんなの願いを叶えてくれる場所。","ENG":"The Promised Land is a place that grants everyone's wishes.","TWN":"樂園是實現每個人願望的地方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"한 번 멸망한 세계가 다시 되살아났다는 건, 누군가 그런 낙원을 소망 했기 때문이라는 걸.","JPN":"一度滅亡した世界が再び蘇ったということは、誰かがそんな楽園を望んだからだってことをね。","ENG":"And if a world that was once destroyed has come back to life... it means someone wished for such a paradise.","TWN":"一個曾經滅亡的世界又復活，是因為有人曾盼望這樣的樂園。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"낙원을 원했던... 첫 번째 사람...","JPN":"楽園を望んだ……最初の人……","ENG":"The one who wished for the Promised Land... the First Resident...","TWN":"第一個……盼望樂園的人……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런 존재가 있다면 사람이 아니라 신이겠네요.","JPN":"そんな存在がいるとしたら、人間じゃなくて神だろうね。","ENG":"If such a being exists, they'd be a god rather than a human.","TWN":"如果有那樣的存在，應該不是人而是神吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런데, 좀 전부터 클라라가 안 보이네.","JPN":"ところで、さっきからクララが見えないけど。","ENG":"By the way, I haven't seen Clara for a while.","TWN":"不過，克拉拉從剛才就不見了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"친구에게 줄 꽃을 찾으러 갔단다.","JPN":"友だちにあげる花を探しに行ってるわよ。","ENG":"She went to look for a flower to give to a friend.","TWN":"她去找要給朋友的花了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어딜 갔대요? 꽃이라면 여기도 취할 정도로 많은데.","JPN":"どこに？　花ならここにもむせかえるほど咲いているのに。","ENG":"Where did she go? There are more than enough flowers here already.","TWN":"她去哪裡啊？這裡不是有很多花嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"황금나무가 있는 곳으로 갔어. 그 주변엔 특별하고 예쁜 꽃이 자란다면서 말이야.","JPN":"黄金の木があるところ。あの近くには特別で綺麗な花が育つんだそうよ。","ENG":"She went to the place where the Golden Tree stands. Saying that special and beautiful flowers grow there.","TWN":"她去黃金樹那裡了，她說那裡有特別漂亮的花。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"특별한 꽃?","JPN":"特別な花？","ENG":"Special?","TWN":"特別的花？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"으음...","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"예쁜 꽃- 예쁜 꽃-","JPN":"綺麗なお花～　綺麗なお花～","ENG":"Pretty flower, pretty flower...","TWN":"漂亮的花－漂亮的花－"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"어디 있지? 안 보여.","JPN":"どこかな？　見つからない。","ENG":"Where is it? I can't see it.","TWN":"在哪裡？找不到耶。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"이걸 찾는 거니?","JPN":"これを探しているの？","ENG":"Are you looking for this?","TWN":"你在找這個嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L21_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"엄청 예쁜 꽃!","JPN":"とっても綺麗なお花！","ENG":"Such a beautiful flower!","TWN":"很漂亮的花！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"맞아. 이거.","JPN":"そう。これ。","ENG":"Yes, this one.","TWN":"對，就是這個。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"친구가 좋아할 거야.","JPN":"友だちが喜ぶよ。","ENG":"My friend will like it.","TWN":"我朋友一定會喜歡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"그런데...","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"누구에요?","JPN":"あなた誰？","ENG":"Who are you?","TWN":"你是誰？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"난...","JPN":"私は……","ENG":"I'm...","TWN":"我是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"아우드라야.","JPN":"アウドラ。","ENG":"Audra.","TWN":"奧德拉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"아우드라...","JPN":"アウドラ……","ENG":"Audra...","TWN":"奧德拉……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"강한 바람이라는 뜻.","JPN":"強い風って意味。","ENG":"It means \\"strong wind.\\"","TWN":"意思是強風。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"맞죠?","JPN":"だよね？","ENG":"Right?","TWN":"對吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"넌, 아나필리스의 언어를 알아?","JPN":"あなた、アナピリスの言葉が分かるの？","ENG":"You understand the language of Anapilis?","TWN":"你會阿納菲莉絲語？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"몰라.","JPN":"分かんない。","ENG":"I dunno.","TWN":"不會。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"그냥 이름에서 느껴졌어요.","JPN":"ただ、名前から感じたの。","ENG":"I just felt it from your name.","TWN":"那只是我從名字感覺到的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"나는, 클라라.","JPN":"私、クララ。","ENG":"I'm Clara.","TWN":"我是克拉拉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"나 꽃 잘 찾아요. 근데 이 꽃은 되게 찾기 힘들어.","JPN":"クララ、お花を探すのが得意。でもこのお花は見つけるのが難しいの。","ENG":"I'm good at finding flowers. But this one is really hard to find.","TWN":"我很會找花，但這種花很難找。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그건 말이지. 낙원에서 딱 한 송이만 자라는 꽃이거든.","JPN":"それはね。この花が楽園でたった一輪しか咲かないからだよ。","ENG":"That's because this flower only grows once in all of the Promised Land.","TWN":"那是因為這朵花在樂園只有一朵。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그리고 아침마다 내가 가져가니까. 네가 못 찾는 것도 당연해.","JPN":"それと、毎朝私が摘んでいくから。あなたが見つけられないのも当然ね。","ENG":"And I pick it every morning. So of course you couldn't find it.","TWN":"而且每天早上都會被我帶走，所以你找不到也很正常。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"언니도 꽃 필요해? 친구한테 주려고?","JPN":"お姉さんもお花が必要なの？　友だちにあげるの？","ENG":"Do you need flowers too? To give to a friend?","TWN":"姐姐也要花嗎？要給朋友嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"난 친구가 없어.","JPN":"私には友だちなんていないよ。","ENG":"I don't have any friends.","TWN":"我沒有朋友。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"내가 먹으려고 꺾는 거야.","JPN":"食べるために摘んでるの。","ENG":"I pick them to eat.","TWN":"我是要摘來吃。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"꽃을... 먹는 거야?","JPN":"お花を……食べるの？","ENG":"You... eat flowers?","TWN":"吃……花？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"이상한 언니였어.","JPN":"変なお姉さん。","ENG":"You're a strange person.","TWN":"真是奇怪的姐姐。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이, 이상하지 않아! 생각보다 맛있고 영양가도 높은 걸?","JPN":"へ、変じゃないよ！　思ったより美味しいし、栄養たっぷりだし。","ENG":"I-I'm not strange! It's tastier and more nutritious than you'd think.","TWN":"不，才不奇怪！那比想像中好吃，也很有營養。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"특별한 병을 고쳐주기도 하고.","JPN":"特別な病を治してくれたりもするの。","ENG":"It can even cure certain special illnesses.","TWN":"還能治療特別的疾病。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"병에 걸렸어?","JPN":"病気なの？","ENG":"Are you sick?","TWN":"你生病了？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"응. 그 꽃을 먹으면 낫는 병이야.","JPN":"うん。その花を食べると治る病気。","ENG":"Yeah. It's an illness that gets better if I eat that flower.","TWN":"嗯，吃了花就能治好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"이 꽃으로 낫는 병...","JPN":"このお花で治る病気……","ENG":"An illness cured by this flower...","TWN":"吃花就能治好的病……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"그럼 돌려줄게.","JPN":"じゃあ、返す。","ENG":"Then I'll give it back.","TWN":"那我還給你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"헤헤, 괜찮아. 병이 나아도 어차피 하루가 지나면 다시 돌아오거든.","JPN":"へへ、大丈夫。病気が治っても、どうせ一日が過ぎたらまた元に戻ってしまうから。","ENG":"Hehe, it's okay. Even if the illness gets better, it just comes back again after a day anyway.","TWN":"呵呵，沒關係。反正就算病好了，隔天又會故態復萌。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"그치만 병에 걸리면 아파.","JPN":"でも、病気になると痛いよ。","ENG":"But being sick hurts.","TWN":"但是生病的話會不舒服。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"당장은 안 나아도 꾹 참고 먹어야 해.","JPN":"すぐには治らなくても、我慢して食べないと。","ENG":"Even if it doesn't help right away, you still have to endure it and eat it.","TWN":"就算當下沒有好轉，也一定要吃下去。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"클라라는 착한 아이구나.","JPN":"クララはいい子だね。","ENG":"Clara, you're a kind girl.","TWN":"克拉拉真是好孩子。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"낙원이 널 이곳으로 데려온 것도 그래서인 모양이네.","JPN":"だから楽園があなたをここに連れてきたんだわ。","ENG":"That must be why the Promised Land brought you here.","TWN":"樂園把你帶到這裡，大概也是這個原因吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"벌레 아저씨가 그랬어.","JPN":"デレおじさんが言ってた。","ENG":"Mr. Belly told me.","TWN":"蟲子大叔說過。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"내가 음식을 맛보고 웃을 수 있는 건, 낙원의 주민이 됐기 때문이래요.","JPN":"クララが食べ物を味わって笑えるのは、楽園の住民になったからだって。","ENG":"He said the reason I can taste food and smile is because I became a resident of the Promised Land.","TWN":"我能嘗到食物的味道後笑出來，就是因為成為樂園居民的緣故。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"맞아. 낙원은 주민들이 바라는 소망을 이루어주거든.","JPN":"そうだよ。楽園は住民の願いを叶えてくれるから。","ENG":"That's right. The Promised Land grants the wishes of its residents.","TWN":"對，樂園會實現居民的願望。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"뭐든지? 전부 다?","JPN":"何でも？　全部？","ENG":"Anything? Everything?","TWN":"什麼都能實現嗎？全部？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"모든 소망을 이뤄주는 건 아냐.","JPN":"願いをすべて叶えてくれるわけじゃないよ。","ENG":"Not every wish.","TWN":"它不會實現所有願望。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"사람의 심상에 깃든 가장 큰 소망은 이루어주지 않은 채로 남겨둬.","JPN":"人の心象に宿っている最も大きな願いは、叶えずにそのまま残しておくの。","ENG":"The greatest wish dwelling in a person's heart is left unfulfilled.","TWN":"它會留下人心中最大的願望。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"왜?","JPN":"どうして？","ENG":"Why?","TWN":"為什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"가장 큰 소망이란 건... 그들이 살아갈 힘을 주는 이유거든.","JPN":"最も大きな願いというものは……その人に生きる力を与えてくれるものだから。","ENG":"Because that greatest wish... is the reason that gives them the strength to keep living.","TWN":"因為最大的願望……是他們活下去的理由。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그래서 마지막의 마지막까지 그 소망만은 간직할 수 있게 남겨두는 거야.","JPN":"だから最後の最後までその願いだけは大事にしまっておけるように、残しておくの。","ENG":"So until the very end, that one wish is left for them to hold onto.","TWN":"所以直到最後一刻，都會保留這個願望。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"...퍼드!","JPN":"……パード！","ENG":"–herd!","TWN":"……牧羊犬！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"들리면... 답해...!","JPN":"聞こえたら……返事して……！","ENG":"If you can hear me... say something...!","TWN":"聽到的話……回答我……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L23_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"방금 누가 날 부른 것 같아.","JPN":"今、誰かに呼ばれた気がする。","ENG":"I think someone just called me.","TWN":"剛才好像有人叫我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"대답하지 않아도 돼.","JPN":"答えなくていいよ。","ENG":"You don't have to answer.","TWN":"不用回答。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그 목소리는 머나먼 미래에서 들려온 메아리일 뿐이니까.","JPN":"その声は、遥か未来から聞こえてきた木霊に過ぎないから。","ENG":"That voice is only an echo carried from a distant future.","TWN":"那個聲音只是從遙遠的未來傳來的回音。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"미래에서 온... 메아리?","JPN":"未来からの……木霊？","ENG":"An echo... from the future?","TWN":"來自未來的……回音？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그 꽃. 친구에게 준다고 했지?","JPN":"その花、友だちにあげるんでしょう？","ENG":"That flower. You said you'd give it to your friend, right?","TWN":"那朵花，你說要送給朋友對吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"같이 갈까?","JPN":"一緒に行こうか？","ENG":"Shall we go together?","TWN":"一起去吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응!","JPN":"うん！","ENG":"Okay!","TWN":"嗯！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"멸망한 세계라고 하기엔, 사람만 없지 멀쩡한 마을처럼 보이는군요.","JPN":"滅亡した世界にしては、人がいないだけで普通の村のようですね。","ENG":"For a world that's supposedly been destroyed, it looks like a perfectly normal village. Minus the people.","TWN":"雖說是毀滅的世界，但只少了人，看起來很像完好的村莊。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"꼭 시간이 멈춘 것 같네요.","JPN":"まるで時間が止まっているみたいです。","ENG":"It's almost as if time has stopped.","TWN":"就像時間停滯了一樣。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그 말이 맞겠지.","JPN":"実際そうなんだろう。","ENG":"That would be correct.","TWN":"應該就像你說的。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"세계의 수명이 다하면 시간의 흐름 또한 멈추게 되니 말이야.","JPN":"世界の寿命が尽きると、時間の流れもまた止まるからな。","ENG":"When a world reaches the end of its lifespan, the flow of time also comes to a halt.","TWN":"當世界的壽命結束，時間也會停止流逝。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"관리자님.","JPN":"最高管理者。","ENG":"Administrator.","TWN":"管理者。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"마왕이 세계를 멸망시키고 가능성을 빼앗았다면, 그렇게 빼앗은 가능성은 전부 어디로 간 걸까요?","JPN":"魔王が世界を滅ぼして可能性を奪ったのなら、そうやって奪った可能性は全部どこに行ったんでしょうか？","ENG":"If the Demon Lord destroyed the world and stole its possibilities, then where did all those stolen possibilities go?","TWN":"魔王毀滅世界奪走了可能性，那些被奪走的可能性去哪了呢？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"여러 가정은 있지만 단언할 수 있는 건 없네.","JPN":"色んな仮説はあるが、断言できることは何もない。","ENG":"There are many hypotheses, but nothing certain.","TWN":"雖然有很多假設，但都無法確定。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"확실한 건, 세계 단위로 축적된 가능성이 타기리온이란 마왕이 가진 손에 쥐어졌을 때 아주 위험해진다는 걸세.","JPN":"確かなのは、世界単位で蓄積された可能性をタギリオンという魔王が手に入れた時、とても危険になるということさ。","ENG":"What we do know is that when possibilities accumulated on a world scale fall into the hands of a Demon Lord like Thagirion, it becomes extremely dangerous.","TWN":"唯一能確定的是，以世界為單位累積的可能性落入塔基里翁手中時，會變得非常危險。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그 가능성의 본질은 카운터의 CRF와 크게 다르지 않은... 순수한 가능성의 결정체이니 말이야.","JPN":"その可能性の本質はカウンターのCRFと大して変わらない……純粋な可能性の結晶体だからな。","ENG":"Because the essence of those possibilities is not very different from a Counter's CRF... the very crystallization of pure possibilities.","TWN":"這些可能性的本質和制裁者CRF差不多……是純粹的可能性結晶。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"셰퍼드!","JPN":"シェパード！","ENG":"Shepherd!","TWN":"牧羊犬！"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L47_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"들리면 대답해!","JPN":"聞こえたら返事して！","ENG":"Answer me if you can hear me!","TWN":"聽到就回答我！"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"셰퍼드!","JPN":"シェパード！","ENG":"Shepherd!","TWN":"牧羊犬！"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"탐지기는 여전히 먹통이군요.","JPN":"探知機には相変わらず何の反応もありませんね。","ENG":"The scanner's still not working.","TWN":"探測器仍然沒反應。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"움직이는 것도 없고, 아티팩트로 추정되는 특이파형도 없어요.","JPN":"動くものもないですし、アーティファクトと推定される特異波形もありません。","ENG":"Nothing's moving, and there aren't even any unusual waveforms that might indicate an Artifact.","TWN":"沒有動靜，也沒任何推斷為人造神器的可疑波形。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그렇다면 불러도 대답할 리 없다는 것쯤은 알 텐데...","JPN":"それなら呼んでも返事をするわけがないということくらい分かっているはずだが……","ENG":"Then you should know calling out won't get an answer...","TWN":"那應該知道就算叫她也不會回答吧……"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"셰퍼드! 들려?","JPN":"シェパード！　聞こえる？","ENG":"Shepherd! Can you hear me?","TWN":"牧羊犬！聽得到嗎？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"...여전히 포기할 생각이 없어 보이네.","JPN":"……相変わらず諦める気はなさそうだな。","ENG":"...Doesn't look like she intends to give up.","TWN":"……看來還不打算放棄呢。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"간신히 찾은 희망이니, 그럴 만도 하잖아요.","JPN":"やっと見つけた希望ですから、無理もありません。","ENG":"It's the first hope she's managed to find. You can't blame her.","TWN":"這是難得找到的希望，自然不會輕易放棄。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"쉽게 포기할 수 없는 인연이니까요.","JPN":"簡単には諦められない絆じゃないですか。","ENG":"It's a bond that's not so easy to abandon.","TWN":"因為是無法輕易割捨的緣分。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"낯설지 않군.","JPN":"見慣れた光景だ。","ENG":"It doesn't feel unfamiliar.","TWN":"一點不陌生。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"엎어지면 코 닿을 곳에 인연이 있는데도, 아무것도 보이지 않아서 헤매는 모습이 말이야.","JPN":"すぐ近くに絆がいるというのに、何も見えずに迷う姿がな。","ENG":"Watching someone wander blindly even though the bond they seek is practically within arm's reach.","TWN":"明明緣分就在眼前，卻因為什麼都見不到而徬徨的模樣。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그렇다는 건...","JPN":"ということは……","ENG":"Does that mean...","TWN":"那表示……"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"공간 좌표 자체는 틀리지 않았다는 걸까요?","JPN":"空間座標自体は間違っていなかったということでしょうか？","ENG":"The space coordinates themselves weren't wrong?","TWN":"空間座標沒錯囉？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうだ。","ENG":"Yes.","TWN":"是啊。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"네가 생각하고 있는 게 맞을 거다.","JPN":"おそらくお前の考えているとおりだろう。","ENG":"What you're thinking is correct.","TWN":"你想的沒錯。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하아... 제발...","JPN":"はあ……お願いだから……","ENG":"*Sigh...* C'mon...","TWN":"唉……拜託……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"대답해 줘. 숨소리라도 좋으니 부디 한 번만...","JPN":"返事して。息の音だけでもいい、どうか一度でも……","ENG":"Answer me. Even if it's just your breathing... please, just once...","TWN":"回答我，哪怕只有呼吸聲也好……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"일단 돌아가지, 스펜서.","JPN":"一旦戻ろう、スペンサー。","ENG":"Let's head back for now, Spencer.","TWN":"先回去吧，史賓瑟。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당장 찾는 건 불가능해.","JPN":"今この場で見つけるのは無理だ。","ENG":"Finding her right now is impossible.","TWN":"不可能馬上找到。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"관리자 씨.","JPN":"管理者さん。","ENG":"Administrator.","TWN":"管理者。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신들이 말하는 인연이란 건... 정확히 어떤 거야?","JPN":"あなたたちの言う絆って……具体的にどんなものなんだ？","ENG":"This bond you speak of... what exactly is it?","TWN":"你說的緣分……到底是什麼？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"말 그대로일세.","JPN":"言葉通りだ。","ENG":"Exactly what it sounds like.","TWN":"就是字面上的意思。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"사람과 사람 사이를 잇는 순리이자 운명이지.","JPN":"人と人を繋ぐ順理であり、運命。","ENG":"The natural order that connects people to one another, and their fate.","TWN":"人與人之間的必然和命運。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그럼...","JPN":"じゃあ……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 앨 못 찾는 건... 나 때문이겠네.","JPN":"あの子が見つからないのは……私のせいね。","ENG":"The reason I can't find her... must be because of me.","TWN":"找不到那孩子，是因為我嗎？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"왜 그렇게 생각하지?","JPN":"どうしてそう思うかね？","ENG":"Why do you think that?","TWN":"你為什麼會這麼想？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 애의 운명을 바꿔버렸거든. 우리 손으로.","JPN":"あの子の運命を変えてしまったから。私たちの手で。","ENG":"Because we changed that child's fate. With our own hands.","TWN":"我們用我們的雙手，改變了她的命運。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우리의 욕심 때문에... 그 인연이 망가지다 못해 끊어져 버린 거야.","JPN":"私たちの欲望が……その絆を壊し、絶ってしまった。","ENG":"Because of our greed... That bond didn't just break. It was completely severed.","TWN":"因為我們的貪心……讓這段緣份毀於一旦。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그 가설은 틀렸네.","JPN":"その仮説は間違っているな。","ENG":"That hypothesis is incorrect.","TWN":"你的假設錯了。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"운명이란 건 그리 쉽게 바뀌지 않거든.","JPN":"運命とは、そう簡単には変わらないものさ。","ENG":"Fate doesn't change so easily.","TWN":"命運不是那麼容易改變的。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그럼 설명이라도 해줘. 어째서 그 아일 만나지 못하는 건데?","JPN":"じゃあ説明してくれないか。どうしてあの子に会えないんだ？","ENG":"Then explain it to me. Why can't I meet her?","TWN":"那麼至少解釋一下，為什麼我們見不到那孩子吧？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그 아이가 이 장소에 있는 건 틀림없어요.","JPN":"その子がこの場所にいるのは間違いありません。","ENG":"There's no mistake that she's here in this place.","TWN":"那孩子確實在這裡。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"단지, 우리와 다른 시간에 있을 뿐이죠.","JPN":"ただ、僕たちとは違う時間にいるんです。","ENG":"She's simply in a different time from us.","TWN":"只是所在的時間與我們不同而已。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"시간이 다르다고?","JPN":"違う時間？","ENG":"A different time?","TWN":"時間不同？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"<color=#ffd34c>세계의 수명이 다하는 건, 시간의 흐름이 멈추는 것과 같다</color>...","JPN":"<color=#ffd34c>世界の寿命が尽きるということは、時間の流れが止まるのと同じ</color>……","ENG":"<color=#ffd34c>When a world reaches the end of its lifespan, it is the same as the flow of time stopping</color>...","TWN":"<color=#ffd34c>世界的壽命結束，就等於時間停止流動</color>……"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"관리자님이 그렇게 말씀하셨잖아요.","JPN":"最高管理者がそう言われたでしょう？","ENG":"That's what you said, Administrator.","TWN":"管理者不是這麼說過嗎？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"세계 단위의 가능성을 손에 쥐고 있는 녀석이라면, 그런 시간의 흐름 정도는 자기 마음대로 멈출 수 있을 겁니다.","JPN":"世界単位の可能性を手に入れた奴なら、時間の流れぐらい思うがままに止めることもできるはずです。","ENG":"If that creature holds the possibilities of an entire world in its grasp, stopping something like the flow of time would be trivial for it.","TWN":"如果手握以世界為單位可能性的傢伙，可以隨心所欲停止時間流動。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"셰퍼드가 과거에 있다니...","JPN":"シェパードが過去にいるなんて……","ENG":"Shepherd's in the past...?","TWN":"牧羊犬竟然在過去……"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"정말 그런 일이 가능하다고 쳐도, 우리가 어떻게 과거로 가지?","JPN":"本当にそんなことができるとして、どうやって過去に行けばいいんだ？","ENG":"Even if that were possible, how are we supposed to go to the past?","TWN":"就算真的有這種事，我們要怎麼回到過去？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아무리 관리국이 대단하다곤 해도 타임머신 같은 게 있을 리...","JPN":"いくら管理局がすごいとはいえ、タイムマシンなんてあるわけ……","ENG":"No matter how amazing the Administration is, it's not like you have a time machine...","TWN":"就算管理局再厲害，也不可能有時光機吧……"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>있다네.</color>","JPN":"<color=#ffd34c>あるんだ。</color>","ENG":"<color=#ffd34c>We do.</color>","TWN":"<color=#ffd34c>有的。</color>"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그게 정말이야? 타임머신이 실존한다고?","JPN":"本当か？　タイムマシンが実在するだって？","ENG":"You're serious? A time machine actually exists?","TWN":"真的嗎？時光機真的存在？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"엄밀히 말하면 흔히 알려진 타임머신이란 개념과는 조금 다르지만...","JPN":"厳密に言えば広く知られているタイムマシンという概念とは少し違うが……","ENG":"Strictly speaking, it's a little different from the common idea of a time machine...","TWN":"嚴格說來，和一般說的時光機概念略有不同……"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"시간선을 오갈 수 있는 장치임엔 분명하다네.","JPN":"時間線を行き来できる装置であることは確かだ。","ENG":"But it is certainly a device that can travel across timelines.","TWN":"但確實是一個可以往返時間線的裝置。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그리고 관리국엔 그런 것들을 다룰 수 있는 스페셜리스트들이 있지.","JPN":"そして管理局には、それらを扱えるスペシャリストたちがいる。","ENG":"And within the Administration, there are specialists capable of operating such things.","TWN":"而管理局裡，就有能駕馭這些東西的專家。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};